# Fourier Transform Filtering Demo# This script shows how to use FFT to apply a High Pass Filter (HPF)# to an image, then reconstruct the image using inverse FFT.import cv2from matplotlib import pyplot as pltimport numpy as np# ---------------------------------------------------# STEP 1: Load image in grayscale# ---------------------------------------------------img = cv2.imread("../data/BSE_Google.jpg", 0)# ---------------------------------------------------# STEP 2: Compute the Fourier Transform# ---------------------------------------------------# OpenCV DFT requires float32 input.# The output has 2 channels:# channel 0 = real part# channel 1 = imaginary partdft = cv2.dft(    np.float32(img),    flags=cv2.DFT_COMPLEX_OUTPUT)# Move the low-frequency components to the center.# Without this, low frequencies are located at the top-left corner.dft_shift = np.fft.fftshift(dft)# Compute the magnitude spectrum.# magnitude = sqrt(real^2 + imaginary^2)# log is used to make the spectrum easier to visualize.magnitude_spectrum = 20 * np.log(    cv2.magnitude(        dft_shift[:, :, 0],        dft_shift[:, :, 1]    ) + 1)# ---------------------------------------------------# STEP 3: Create a circular High Pass Filter mask# ---------------------------------------------------# Get image sizerows, cols = img.shape# Find the center of the imagecrow, ccol = rows // 2, cols // 2# Start with a mask full of 1s.# Shape is (rows, cols, 2) because DFT has real and imaginary channels.mask = np.ones((rows, cols, 2), np.uint8)# Radius of the blocked center arear = 80# Create coordinate gridsx, y = np.ogrid[:rows, :cols]# Select pixels inside the center circlemask_area = (x - crow) ** 2 + (y - ccol) ** 2 <= r ** 2# Set the center circle to 0.# This blocks low frequencies.mask[mask_area] = 0# ---------------------------------------------------# STEP 4: Apply the mask in frequency space# ---------------------------------------------------# Multiplying by the mask removes selected frequencies.# 1 means keep the frequency.# 0 means remove the frequency.fshift = dft_shift * mask# Visualize the filtered frequency spectrumfshift_mask_mag = 20 * np.log(    cv2.magnitude(        fshift[:, :, 0],        fshift[:, :, 1]    ) + 1)# ---------------------------------------------------# STEP 5: Inverse Fourier Transform# ---------------------------------------------------# Move the frequency spectrum back to OpenCV's original FFT layoutf_ishift = np.fft.ifftshift(fshift)# Convert frequency space back to image spaceimg_back = cv2.idft(f_ishift)# Convert complex output back to magnitude imageimg_back = cv2.magnitude(    img_back[:, :, 0],    img_back[:, :, 1])# ---------------------------------------------------# STEP 6: Display results# ---------------------------------------------------fig = plt.figure()ax1 = fig.add_subplot(1, 2, 1)ax1.imshow(img, cmap="gray")ax1.set_title("Input Image")ax1.axis("off")ax2 = fig.add_subplot(1, 2, 2)ax2.imshow(magnitude_spectrum, cmap="gray")ax2.set_title("FFT of Image")ax2.axis("off")fig = plt.figure()ax3 = fig.add_subplot(1, 2, 1)ax3.imshow(fshift_mask_mag, cmap="gray")ax3.set_title("FFT After High Pass Filter")ax3.axis("off")ax4 = fig.add_subplot(1, 2, 2)ax4.imshow(img_back, cmap="gray")ax4.set_title("After Inverse FFT")ax4.axis("off")plt.tight_layout()plt.show()